	@Test
	void serviceCalculatesTotalWhenMissingAndFallsBackToDefaultLimit() throws Exception {
		TrackingExploreServlet servlet = new TrackingExploreServlet(42);
		CookieHandler cookies = mock(CookieHandler.class);
		WorkbenchRequest request = mock(WorkbenchRequest.class);
		HttpServletResponse response = mock(HttpServletResponse.class);
		TupleResultBuilder builder = mock(TupleResultBuilder.class);
		Value value = SimpleValueFactory.getInstance().createIRI("urn:test:resource");

		servlet.setCookieHandler(cookies);
		when(request.getValue("resource")).thenReturn(value);
		when(request.getInt("know_total")).thenReturn(0);
		when(request.getInt("offset")).thenReturn(4);
		when(request.isParameterPresent(ExploreServlet.LIMIT)).thenReturn(false);

		servlet.service(request, response, builder, mock(RepositoryConnection.class));

		assertThat(servlet.calls).hasSize(2);
		assertThat(servlet.calls.get(0).value).isEqualTo(value);
		assertThat(servlet.calls.get(0).offset).isZero();
		assertThat(servlet.calls.get(0).limit).isEqualTo(Integer.MAX_VALUE);
		assertThat(servlet.calls.get(0).render).isFalse();
		assertThat(servlet.calls.get(1).value).isEqualTo(value);
		assertThat(servlet.calls.get(1).offset).isEqualTo(4);
		assertThat(servlet.calls.get(1).limit).isEqualTo(ExploreServlet.LIMIT_DEFAULT);
		assertThat(servlet.calls.get(1).render).isTrue();
		verify(cookies).addTotalResultCountCookie(request, response, 42);
	}

