	@Test
	void processResourceSupportsLiteralOnlyLookups() throws Exception {
		ExploreServlet servlet = new ExploreServlet();
		RepositoryConnection connection = mock(RepositoryConnection.class);
		TupleResultBuilder builder = mock(TupleResultBuilder.class);
		Value literal = SimpleValueFactory.getInstance().createLiteral("literal");
		Statement statement = SimpleValueFactory.getInstance()
				.createStatement(
						SimpleValueFactory.getInstance().createIRI("urn:test:subject"),
						SimpleValueFactory.getInstance().createIRI("urn:test:predicate"), literal);
		when(connection.getStatements(null, null, literal, true)).thenReturn(repositoryResult(statement));

		ExploreServlet.ResultCursor cursor = servlet.processResource(connection, builder, literal, 0, 1, true);

		assertThat(cursor.getTotalResultCount()).isEqualTo(1);
		assertThat(cursor.getRenderedResultCount()).isEqualTo(1);
		verify(builder).result(statement.getSubject(), statement.getPredicate(), statement.getObject(),
				statement.getContext());
	}

	@Test
	void resultCursorHandlesNegativeOffsetUnlimitedLimitAndDisabledRendering() {
		ExploreServlet servlet = new ExploreServlet();
		ExploreServlet.ResultCursor unlimited = servlet.new ResultCursor(-5, 0, true);

		assertThat(unlimited.mayRender()).isTrue();
		unlimited.advance();
		assertThat(unlimited.getTotalResultCount()).isEqualTo(1);
		assertThat(unlimited.getRenderedResultCount()).isEqualTo(1);

		ExploreServlet.ResultCursor hidden = servlet.new ResultCursor(2, 1, false);
		assertThat(hidden.mayRender()).isFalse();
		hidden.advance();
		hidden.advance();
		hidden.advance();
		assertThat(hidden.getTotalResultCount()).isEqualTo(3);
		assertThat(hidden.getRenderedResultCount()).isZero();

		ExploreServlet.ResultCursor delayed = servlet.new ResultCursor(1, 1, true);
		assertThat(delayed.mayRender()).isFalse();
		delayed.advance();
		assertThat(delayed.mayRender()).isTrue();
		delayed.advance();
		assertThat(delayed.mayRender()).isFalse();
		assertThat(delayed.getRenderedResultCount()).isEqualTo(1);
	}

