	private static RepositoryResult<Namespace> emptyNamespaces() {
		return new RepositoryResult<>(new CloseableIteratorIteration<>(List.<Namespace>of().iterator()));
	}

	private static RepositoryResult<Statement> repositoryResult(Statement... statements) {
		return new RepositoryResult<>(new CloseableIteratorIteration<>(List.of(statements).iterator()));
	}

	private static final class TrackingExploreServlet extends ExploreServlet {
		private final List<Call> calls = new ArrayList<>();
		private final int totalCount;

		private TrackingExploreServlet(int totalCount) {
			this.totalCount = totalCount;
		}

		private void setCookieHandler(CookieHandler cookies) {
			this.cookies = cookies;
		}

		@Override
		protected ResultCursor processResource(RepositoryConnection con, TupleResultBuilder builder, Value value,
				int offset, int limit, boolean render) {
			calls.add(new Call(value, offset, limit, render));
			ResultCursor cursor = new ResultCursor(0, 0, false);
			for (int i = 0; i < totalCount; i++) {
				cursor.advance();
			}
			return cursor;
		}

		private static final class Call {
			private final Value value;
			private final int offset;
			private final int limit;
			private final boolean render;

			private Call(Value value, int offset, int limit, boolean render) {
				this.value = value;
				this.offset = offset;
				this.limit = limit;
				this.render = render;
			}
		}
	}

